    bookingCity: `Kathmandu`,
    seoTitle: `Gadhimai Temple Bara Nepal | Pilgrimage Site & Gadhimai Mela Guide`,
    seoDescription: `Visit Gadhimai Temple in Bara, Nepal — one of South Asia's most powerful Hindu pilgrimage sites dedicated to Goddess Gadhimai. Learn about the Gadhimai Mela festival, its history, reforms, and how to visit.`,
    published: true,
